import{_ as e,o as a,c as i,a2 as o}from"./chunks/framework.Crpw6aS5.js";const m=JSON.parse('{"title":"Email Expiration","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/expiration.md","filePath":"en/guide/expiration.md"}'),r={name:"en/guide/expiration.md"};function d(n,t,s,l,c,h){return a(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="email-expiration" tabindex="-1">Email Expiration <a class="header-anchor" href="#email-expiration" aria-label="Permalink to &quot;Email Expiration&quot;">​</a></h1><p>The expiration feature lets you mark certain emails as <strong>temporary</strong> so they are automatically deleted after a defined period. This is particularly useful for emails that lose their value after a certain time.</p><h2 id="temporary-email-types" tabindex="-1">Temporary Email Types <a class="header-anchor" href="#temporary-email-types" aria-label="Permalink to &quot;Temporary Email Types&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Category</th><th>Description</th><th style="text-align:center;">Default Duration</th></tr></thead><tbody><tr><td><strong>OTP Code</strong></td><td>Verification codes, 2FA, sign-in</td><td style="text-align:center;">1 day</td></tr><tr><td><strong>Delivery</strong></td><td>Package tracking, shipping confirmations</td><td style="text-align:center;">14 days</td></tr><tr><td><strong>Promotion</strong></td><td>Flash offers, promo codes, sales</td><td style="text-align:center;">7 days</td></tr><tr><td><strong>Manual</strong></td><td>Any manually marked email</td><td style="text-align:center;">7 days</td></tr></tbody></table><h2 id="automatic-detection" tabindex="-1">Automatic Detection <a class="header-anchor" href="#automatic-detection" aria-label="Permalink to &quot;Automatic Detection&quot;">​</a></h2><p>Click <strong>Detect automatically</strong> to scan your recent emails. The application analyzes the subject and sender of each email to identify temporary emails using heuristics:</p><ul><li><strong>OTP Codes</strong>: detection by keywords (verification, code, OTP, sign-in, security) and senders (noreply, security)</li><li><strong>Deliveries</strong>: detection by keywords (shipping, tracking, package, order) and known carriers (UPS, FedEx, DHL, Colissimo)</li><li><strong>Promotions</strong>: detection by keywords (promo, sale, discount, offer) and marketing senders</li></ul><p>After detection, you can select which emails to mark as temporary and adjust the duration if needed.</p><h2 id="manual-addition" tabindex="-1">Manual Addition <a class="header-anchor" href="#manual-addition" aria-label="Permalink to &quot;Manual Addition&quot;">​</a></h2><p>You can also manually add an email to the expiration list:</p><ol><li>Click <strong>Add manually</strong></li><li>Enter the Gmail message ID</li><li>Choose the category</li><li>Set the number of days before expiration</li></ol><h2 id="dashboard" tabindex="-1">Dashboard <a class="header-anchor" href="#dashboard" aria-label="Permalink to &quot;Dashboard&quot;">​</a></h2><p>The page displays 4 statistics:</p><ul><li><strong>Pending</strong>: marked emails that have not yet expired</li><li><strong>Expiring soon</strong>: emails expiring within the next 24 hours</li><li><strong>Deleted</strong>: emails already automatically deleted</li><li><strong>Total</strong>: total number of expirations created</li></ul><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><p>The system checks expirations <strong>every 15 minutes</strong>. When an email reaches its expiration date, it is automatically sent to the Gmail trash (no permanent deletion, which leaves 30 days to recover).</p><h2 id="api" tabindex="-1">API <a class="header-anchor" href="#api" aria-label="Permalink to &quot;API&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Endpoint</th><th>Description</th></tr></thead><tbody><tr><td><code>GET</code></td><td><code>/api/expiration/:accountId</code></td><td>List expirations</td></tr><tr><td><code>GET</code></td><td><code>/api/expiration/:accountId/stats</code></td><td>Statistics</td></tr><tr><td><code>POST</code></td><td><code>/api/expiration/:accountId</code></td><td>Create an expiration</td></tr><tr><td><code>POST</code></td><td><code>/api/expiration/:accountId/batch</code></td><td>Batch create</td></tr><tr><td><code>POST</code></td><td><code>/api/expiration/:accountId/detect</code></td><td>Heuristic detection</td></tr><tr><td><code>PATCH</code></td><td><code>/api/expiration/:accountId/:id</code></td><td>Modify the date</td></tr><tr><td><code>DELETE</code></td><td><code>/api/expiration/:accountId/:id</code></td><td>Delete the expiration</td></tr></tbody></table>',18)])])}const u=e(r,[["render",d]]);export{m as __pageData,u as default};
